import base64
import json
import logging
import os
from typing import Any, Dict, Optional

from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import storage

logging.basicConfig(level=logging.INFO)

PROJECT_ID = os.getenv("GCP_PROJECT") or os.getenv("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.getenv("PUBSUB_TOPIC", "file-processed")
FIRESTORE_COLLECTION = os.getenv("FIRESTORE_COLLECTION", "processed_files")

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher_client = pubsub_v1.PublisherClient()


def _read_blob_text(bucket_name: str, file_name: str) -> str:
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    return blob.download_as_text()


def _write_firestore(document_id: str, data: Dict[str, Any]) -> None:
    firestore_client.collection(FIRESTORE_COLLECTION).document(document_id).set(data)


def _publish_message(payload: Dict[str, Any]) -> str:
    topic_path = publisher_client.topic_path(PROJECT_ID, PUBSUB_TOPIC)
    future = publisher_client.publish(
        topic_path,
        json.dumps(payload).encode("utf-8"),
        content_type="application/json",
    )
    return future.result()


def process_gcs_file(event: Dict[str, Any], context: Optional[Any]) -> None:
    bucket_name = event["bucket"]
    file_name = event["name"]
    generation = event.get("generation")
    metageneration = event.get("metageneration")
    time_created = event.get("timeCreated")
    updated = event.get("updated")

    logging.info("Processing gs://%s/%s", bucket_name, file_name)

    content = _read_blob_text(bucket_name, file_name)

    document_id = base64.urlsafe_b64encode(f"{bucket_name}/{file_name}".encode("utf-8")).decode("utf-8")
    firestore_payload = {
        "bucket": bucket_name,
        "name": file_name,
        "generation": generation,
        "metageneration": metageneration,
        "timeCreated": time_created,
        "updated": updated,
        "size_bytes": len(content.encode("utf-8")),
        "preview": content[:1000],
        "status": "processed",
    }
    _write_firestore(document_id, firestore_payload)

    pubsub_payload = {
        "bucket": bucket_name,
        "name": file_name,
        "documentId": document_id,
        "status": "processed",
    }
    message_id = _publish_message(pubsub_payload)

    logging.info(
        "Completed processing gs://%s/%s firestore_doc=%s pubsub_message_id=%s",
        bucket_name,
        file_name,
        document_id,
        message_id,
    )